export function getClipsByCategory(category) {
  return Object.values(MOTION_CLIPS).filter(c => c.category === category);
}

export function searchClips(query) {
  if (!query) return Object.values(MOTION_CLIPS);
  const q = query.toLowerCase();
  return Object.values(MOTION_CLIPS).filter(c =>
    c.id.includes(q) ||
    c.label.toLowerCase().includes(q) ||
    c.category.toLowerCase().includes(q) ||
    c.tags.some(t => t.includes(q))
  );
}

export function getClipBVH(id) {
  return MOTION_CLIPS[id]?.bvh ?? null;
}

export function getClipMeta(id) {
  const c = MOTION_CLIPS[id];
  if (!c) return null;
  const { bvh, ...meta } = c;
  return meta;
}

export default MOTION_CLIPS;